const e={klipperscreenStudio:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Bearbeite die KlipperScreen-Touchscreen-Konfiguration deines Druckers sicher und starte KlipperScreen neu, um sie anzuwenden. Jeder Speichervorgang wird zuvor gesichert."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"So funktioniert es"}},body:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf steuert den am Drucker angeschlossenen Touchscreen — Theme, Sprache, Menüs und Anzeigeoptionen. Dieser Editor liest und schreibt die Datei über denselben sicheren Pfad wie der Config-Editor."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Bearbeite den Konfigurationstext unten (oder lass ihn unverändert)."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Speichern — die Datei wird zuerst gesichert, und das Speichern wird abgelehnt, während der Drucker beschäftigt ist."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Starte KlipperScreen neu, um die Änderung auf dem Bildschirm anzuwenden."}},lfNote:{t:0,b:{t:2,i:[{t:3}],s:"Zeilen verwenden UNIX-Zeilenenden (LF), die beim Speichern automatisch erzwungen werden."}}},status:{checking:{t:0,b:{t:2,i:[{t:3}],s:"Suche nach KlipperScreen…"}},absent:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen wurde auf diesem Drucker nicht erkannt (keine KlipperScreen.conf, und nicht von Moonraker gemeldet). Installiere KlipperScreen, um dieses Werkzeug zu nutzen."}},present:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen erkannt"}},theme:{t:0,b:{t:2,i:[{t:3}],s:"Theme"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Sprache"}},notRestartable:{t:0,b:{t:2,i:[{t:3}],s:"Moonraker kann KlipperScreen nicht automatisch neu starten — starte es nach dem Speichern manuell neu."}}},editor:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Lese KlipperScreen.conf…"}},reload:{t:0,b:{t:2,i:[{t:3}],s:"Neu laden"}},save:{t:0,b:{t:2,i:[{t:3}],s:"Konfig speichern"}},saving:{t:0,b:{t:2,i:[{t:3}],s:"Speichere…"}},saved:{t:0,b:{t:2,i:[{t:3}],s:"Gespeichert (gesichert)"}},unsaved:{t:0,b:{t:2,i:[{t:3}],s:"Ungespeicherte Änderungen"}}},save:{busy:{t:0,b:{t:2,i:[{t:3}],s:"Abgelehnt, während der Drucker beschäftigt ist — versuche es erneut im Leerlauf."}},stale:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf wurde seit dem Laden auf der Festplatte geändert (wahrscheinlich am Bildschirm bearbeitet). Lade neu, bevor du speicherst, um diese Änderung nicht zu überschreiben."}}},view:{config:{t:0,b:{t:2,i:[{t:3}],s:"Konfig"}},themes:{t:0,b:{t:2,i:[{t:3}],s:"Themes"}}},themes:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Lade Themes…"}},palette:{t:0,b:{t:2,i:[{t:3}],s:"Palette"}},radius:{t:0,b:{t:2,i:[{t:3}],s:"Eckenradius"}},preview:{t:0,b:{t:2,i:[{t:3}],s:"Live-Vorschau"}},btn:{t:0,b:{t:2,i:[{t:3}],s:"Knopf"}},previewWarn:{t:0,b:{t:2,i:[{t:3}],s:"Warnung"}},previewApprox:{t:0,b:{t:2,i:[{t:3}],s:"Ungefähre Vorschau — der echte Bildschirm rendert mit GTK; kleine Abweichungen sind normal."}},namePlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Name des neuen Themes"}},createApply:{t:0,b:{t:2,i:[{t:3}],s:"Erstellen & anwenden"}},createOnly:{t:0,b:{t:2,i:[{t:3}],s:"Nur erstellen"}},installed:{t:0,b:{t:2,i:[{t:3}],s:"Installierte Themes"}},apply:{t:0,b:{t:2,i:[{t:3}],s:"Anwenden"}},delete:{t:0,b:{t:2,i:[{t:3}],s:"Theme löschen"}},generated:{t:0,b:{t:2,i:[{t:3}],s:"Hier erstellt"}},created:{t:0,b:{t:2,i:[{t:3}],s:"Theme erstellt. Wende es aus der Liste an, dann neu starten."}},appliedRestart:{t:0,b:{t:2,i:[{t:3}],s:"Theme gesetzt — starte KlipperScreen neu, um es zu sehen."}}},restart:{button:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen neu starten"}},restarting:{t:0,b:{t:2,i:[{t:3}],s:"Starte neu…"}},done:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen startet neu — der Bildschirm lädt gleich neu."}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen neu starten?"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Dies startet den Touchscreen-Dienst neu, um deine Änderungen anzuwenden. Ein laufender Druck ist nicht betroffen, aber der Bildschirm wird einige Sekunden schwarz."}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Neu starten"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Abbrechen"}}}}};export{e as default};
